#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int countGoodPermutations(int *arr, int n, int d) {
    int count = 0;
    for (int i = 0; i < n; i++) {
        int temp = arr[i];
        arr[i] = -1;
        for (int j = 0; j < n; j++) {
            if (arr[j] == -1) continue;
            int k = j + 1;
            while (k < n && arr[k] == -1) k++;
            if (k < n && arr[j] + d > arr[k]) {
                count++;
            }
        }
        arr[i] = temp;
    }
    return count;
}

int main() {
    int n, d, m;
    scanf("%d %d", &n, &d);
    int *arr = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    scanf("%d", &m);
    for (int i = 0; i < m; i++) {
        int p, v;
        scanf("%d %d", &p, &v);
        arr[p - 1] = v;
        printf("%d\n", countGoodPermutations(arr, n, d) % MOD);
    }
    return 0;
}

